__attribute__((noinline))
class_T bench_block(class_T data_val, class_T f_val) {
    class_T sum = 0;
    class_T f = f_val;
    class_T t = data_val;

    for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
        t = t * t + f;
    }
    sum += t;
    return sum;
}

__kernel void benchmark_func(class_T seed, __global class_T* src) {
    size_t global_id = get_global_id(0);
    size_t global_size = get_global_size(0);

    // Calculate the number of elements this workitem must process
    size_t chunk_size = ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t start_idx = global_id * chunk_size;

    class_T acc = 0;

    // Process the contiguous chunk of data assigned to this workitem
    for (size_t k = 0; k < chunk_size; k++) {
        size_t idx = start_idx + k;
        // Bounds check to prevent out-of-range access if the total size is not perfectly aligned
        if (idx < (global_size * chunk_size)) {
            class_T val = src[idx];
            class_T t = val;

            // Perform the computation iterations
            for (size_t j = 0; j < COMPUTE_ITERATIONS; j++) {
                t = t * t + seed;
            }
            acc += t;
        }
    }

    // Write the accumulated result back to the first element of this workitem's chunk
    // This avoids race conditions while ensuring a write operation occurs
    if (global_id < global_size) {
        src[start_idx] = acc;
    }
}

